export default function EditMediaPage(props) {
    const dispatch = useDispatch()
    const { state } = useLocation()

    // const [data, setData] = useState([]);
    const navigate = useNavigate()

    const [workoutData, setWorkoutData] = useOutletContext()
    const [showDetails, setShowDwtails] = useState(true)
    const [bottomBox, setBottomBox] = useState(true)

    let Exercise = workoutData.Exercise[state.index]

    const [currentExercise, setCurrentExercise] = useState(0)

    const [exercise, setExercise] = useState(
        state.file ? [...state.file] : Exercise?.media
    )

    const setMuscellData = (mdata) => {
        editExercise({ triggerMuscle: [...mdata] }, state.index)
    }

    const styles = {
        slideContainer: {
            height: '100vh',
            textShadow: '0px 2px 2px rgba(43, 64, 87, 0.25)',
        },
        slide: {
            minHeight: '100vh',
            color: '#fff',
        },
        slide1: {
            background: '#FEA900',
        },
        slide2: {
            background: '#B3DC4A',
        },
        slide3: {
            background: '#000',
        },
    }

    const editExercise = (val, index) => {
        let program = { ...workoutData }
        program.Exercise[index] = {
            ...program.Exercise[index],
            ...val,
        }
        setWorkoutData(program)
    }

    const uploadVideo = async (File) => {
        const file = File
        const fileName = file.name
        const fileSize = file.size.toString()
        let id = new Date().getTime()
        // const response = await axios({
        //   method: "get",
        //   url: `${api.protocol}${api.baseUrl}misc/upload-video?fileSize=${fileSize}`,
        // });

        // const id = response.data.data.upload.upload_link;
        // Create a new tus upload

        const formData = new FormData()
        formData.append('file', file)

        let upload = axios
            .post(`${api.protocol}${api.baseUrl}${api.getSignedUrl}`, {
                title: Exercise?.title,
                name: file.name,
                type: 'application/octet-stream',
            })
            .then((res) => {
                const CancelToken = Axios.CancelToken
                const source = CancelToken.source()
                dispatch(
                    updateRecord(id, {
                        source: source,
                        ...state,
                    })
                )
                Axios.put(res.data, file, {
                    cancelToken: source.token,
                    headers: { 'Content-Type': 'application/octet-stream' },
                    onUploadProgress: (progressEvent) => {
                        dispatch(
                            updateRecord(id, {
                                upload: upload,

                                progress: Math.round(
                                    (progressEvent.loaded /
                                        progressEvent.total) *
                                        100
                                ),
                                ...state,
                            })
                        )
                    },
                })
                    .then((response) => {
                        editExercise(
                            {
                                media: workoutData.Exercise[state.index].media
                                    ? [
                                          ...workoutData.Exercise[state.index]
                                              .media,
                                          res.data.split('?')[0],
                                      ]
                                    : [res.data.split('?')[0]],
                            },
                            state.index
                        )
                        dispatch(deleteRecord(id))
                    })
                    .catch((err) => {
                        dispatch(deleteRecord(id))
                    })
            })

            .catch((err) => {
                console.log(err)
                dispatch(deleteRecord(id))
                dispatch(
                    updateFeedback({
                        message: 'Error uploading video',
                        type: 'error',
                    })
                )
            })

        // const upload = new tus.Upload(file, {
        //   endPoint: "https://api.vimeo.com/me/videos",
        //   uploadUrl: response.data.data.upload.upload_link,
        //   retryDelays: [0, 3000, 5000, 10000, 20000],
        //   metadata: {
        //     filename: file.name,
        //     filetype: file.type,
        //   },
        //   headers: {},
        //   onError: function (error) {},
        //   onProgress: function (bytesUploaded, bytesTotal) {
        //     let percentage = ((bytesUploaded / bytesTotal) * 100).toFixed(2);

        //     dispatch(
        //       updateRecord(id, {
        //         upload: upload,
        //         progress: percentage,
        //         ...state,
        //         details: {
        //           url: response.data.data.link,
        //         },
        //       })
        //     );
        //   },
        //   onSuccess: function () {
        //     editExercise(
        //       {
        //         media: Program.ExercisePlan.weeks[state.week].days[state.day]
        //           .Exercise[state.index].media
        //           ? [
        //               ...Program.ExercisePlan.weeks[state.week].days[state.day]
        //                 .Exercise[state.index].media,
        //               response.data.data.link,
        //             ]
        //           : [response.data.data.link],
        //       },
        //       state.index
        //     );
        //     dispatch(deleteRecord(id));
        //   },
        // });

        // Start the upload
        // upload.start();
    }

    const uploadAll = async () => {
        dispatch(updateFeedback({ loading: true }))
        for (const file of [...exercise].filter((i) => typeof i !== 'string')) {
            await uploadVideo(file)
        }
        dispatch(updateFeedback({ loading: false }))
        navigate(-1)
    }

    const addNewVideo = (e) => {
        setExercise([...exercise, ...e.target.files])
    }

    const removeVideo = (indexR) => {
        if (typeof exercise[indexR] == 'string') {
            deleteOneVideo(exercise[indexR])
        } else {
            if (currentExercise == indexR && currentExercise) {
                setCurrentExercise(currentExercise - 1)
            }
        }
        let AllExercise = [...exercise]
        AllExercise.splice(indexR, 1)
        setExercise(AllExercise)
    }

    const deleteOneVideo = (item) => {
        dispatch(deleteVideos([item.split('https://vimeo.com/')[1]]))
            .then((res) => {
                editExercise(
                    { media: Exercise?.media.filter((i) => i !== item) },
                    state.index
                )
            })
            .catch((err) => {
                if (err.response.status == 404) {
                    editExercise(
                        { media: Exercise?.media.filter((i) => i !== item) },
                        state.index
                    )
                }
            })
    }

    useEffect(() => {
        if (Exercise?.media?.length == 0 || !Exercise?.media) {
            editExercise({ triggerMuscle: [] }, state.index)
        }
    }, [])

    let uploadableFiles = [...exercise].filter((i) => typeof i !== 'string')

    return (
        <Page title=" Simplified Online Fitness Training ">
            <input
                type="file"
                accept="video/*"
                style={{ display: 'none' }}
                id={'media-add-new-video'}
                onChange={addNewVideo}
            />
            <RootStyle>
                <Container>
                    <div style={Object.assign({}, styles.slide, styles.slide3)}>
                        <Box position={'relative'}>
                            {' '}
                            <Box
                                style={{
                                    width: '100vw',
                                    height: '100vh',
                                    position: 'relative',
                                    display: 'flex',
                                    justifyContent: 'center',
                                    alignItems: 'center',
                                }}
                            >
                                {exercise?.[currentExercise] &&
                                typeof exercise?.[currentExercise] ==
                                    'string' ? (
                                    <ReactPlayerVimeo
                                        url={getProcessedvideoLink(
                                            exercise?.[currentExercise]
                                                ? exercise[currentExercise]
                                                : ''
                                        )}
                                        raw={
                                            exercise?.[currentExercise]
                                                ? exercise[currentExercise]
                                                : ''
                                        }
                                        //   controls
                                        loop
                                        controls={false}
                                        // autoPlay={true}
                                        responsive={true}
                                        playsinline={true}
                                        playing={true}
                                        width="100vw"
                                        height={'100vh'}
                                        style={{
                                            zIndex: 0,

                                            display: 'flex',
                                            justifyContent: 'center',
                                            alignItems: 'center',
                                            width: '100vw',
                                            height: '100vh',
                                            '& video': {
                                                width: '100vw',
                                                height: '100vh',
                                            },
                                        }}
                                    />
                                ) : (
                                    <ReactPlayer
                                        url={
                                            exercise?.[currentExercise]
                                                ? URL.createObjectURL(
                                                      exercise[currentExercise]
                                                  )
                                                : ''
                                        }
                                        //   controls
                                        loop
                                        controls={false}
                                        // autoPlay={true}
                                        responsive={true}
                                        playsinline={true}
                                        playing={true}
                                        width="100vw"
                                        height={'auto'}
                                        style={{
                                            display: 'flex',
                                            justifyContent: 'center',
                                            alignItems: 'center',
                                            width: '100vw',
                                            height: '100vh',
                                            '& video': {},
                                        }}
                                    />
                                )}
                            </Box>
                            <Box
                                position={'absolute'}
                                zIndex={1000}
                                width={'100vw'}
                                height={'100vh'}
                                top={0}
                                onClick={() => setShowDwtails(!showDetails)}
                            >
                                <TopBox>
                                    <IconButton
                                        onClick={() => navigate(-1)}
                                        sx={{ color: 'common.white' }}
                                    >
                                        <ArrowLeft />
                                    </IconButton>
                                    &nbsp;
                                    <Typography
                                        variant="subtitle1"
                                        color="common.white"
                                    >
                                        Exercise {state.index + 1}
                                    </Typography>
                                </TopBox>
                                <Box
                                    style={{
                                        position: 'absolute',
                                        top: '50vh',
                                        right: 0,
                                        paddingRight: 10,
                                    }}
                                ></Box>

                                {showDetails && (
                                    <BottomBox
                                        style={{
                                            display: bottomBox
                                                ? 'block'
                                                : 'none',
                                        }}
                                        onClick={(e) => e.stopPropagation()}
                                    >
                                        <MuscleHighlighterDrawer
                                            setMData={setMuscellData}
                                            data={[
                                                {
                                                    muscles:
                                                        Exercise?.triggerMuscle ||
                                                        [],
                                                },
                                            ]}
                                        >
                                            <Box
                                                display={'flex'}
                                                alignItems={'center'}
                                            >
                                                <Model
                                                    data={[
                                                        {
                                                            name:
                                                                Exercise?.title ||
                                                                '',
                                                            muscles:
                                                                Exercise?.triggerMuscle ||
                                                                [],
                                                            frequency: 1,
                                                        },
                                                    ]}
                                                    style={{
                                                        width: '68px',
                                                        padding: '5px',
                                                    }}
                                                    highlightedColors={[
                                                        '#EE3737',
                                                    ]}
                                                />
                                                <Model
                                                    type="posterior"
                                                    data={[
                                                        {
                                                            name: Exercise?.title,
                                                            muscles:
                                                                Exercise?.triggerMuscle ||
                                                                [],
                                                            frequency: 1,
                                                        },
                                                    ]}
                                                    style={{
                                                        width: '68px',
                                                        padding: '5px',
                                                    }}
                                                    highlightedColors={[
                                                        '#EE3737',
                                                    ]}
                                                />
                                            </Box>
                                        </MuscleHighlighterDrawer>

                                        <Box width="100%" marginLeft={'5px'}>
                                            <InputBase
                                                placeholder="Title here"
                                                fullWidth
                                                defaultValue={Exercise?.title}
                                                onBlur={(e) =>
                                                    editExercise(
                                                        {
                                                            title: e.target
                                                                .value,
                                                        },
                                                        state.index
                                                    )
                                                }
                                                sx={{
                                                    py: 0.25,
                                                    fontSize: 18,
                                                    color: 'common.white',
                                                }}
                                            />
                                            <InputBase
                                                placeholder="Description here"
                                                fullWidth
                                                defaultValue={Exercise?.note}
                                                onBlur={(e) =>
                                                    editExercise(
                                                        {
                                                            note: e.target
                                                                .value,
                                                        },
                                                        state.index
                                                    )
                                                }
                                                multiline
                                                minRows={2}
                                                sx={{
                                                    py: 0.25,
                                                    fontSize: 16,
                                                    color: 'common.white',
                                                }}
                                            />
                                        </Box>
                                        <CreateMediaCarousel
                                            videos={exercise}
                                            currentExercise={currentExercise}
                                            setCurrent={(i) => {
                                                setCurrentExercise(i)
                                            }}
                                            removeVideo={removeVideo}
                                        />
                                        <Box
                                            display={'flex'}
                                            justifyContent="space-between"
                                            //   color={"#000"}
                                            alignItems={'center'}
                                            style={{
                                                color: '#959FAB !important',
                                            }}
                                        >
                                            <Box
                                                display={'flex'}
                                                alignItems={'center'}
                                                ml={2}
                                            >
                                               
                                                        <Typography
                                                            variant="subtitle1"
                                                            color={
                                                                exercise?.length >
                                                                0
                                                                    ? 'common.white'
                                                                    : 'muted.text'
                                                            }
                                                        >
                                                            {exercise?.length ??
                                                                0}
                                                        </Typography>
                                              
                                                <Typography ml={1}>
                                                    Media uploaded
                                                </Typography>
                                            </Box>
                                            <Button
                                                disabled={
                                                    exercise?.length == 0 ||
                                                    !exercise
                                                }
                                                variant="contained"
                                                // color={exercise?.length ? "primary" : "muted"}
                                                onClick={uploadAll}
                                                endIcon={
                                                    <Iconify
                                                        icon="ph:caret-circle-right-light"
                                                        color={
                                                            exercise?.length > 0
                                                                ? 'common.white'
                                                                : 'muted.text'
                                                        }
                                                        width="24px"
                                                        height="24px"
                                                    />
                                                }
                                            >
                                                <Typography
                                                    variant="body1"
                                                    color={
                                                        exercise?.length > 0
                                                            ? 'common.white'
                                                            : 'muted.text'
                                                    }
                                                >
                                                    {uploadableFiles.length
                                                        ? 'Upload'
                                                        : 'Done'}
                                                </Typography>
                                                &nbsp;
                                            </Button>
                                        </Box>
                                    </BottomBox>
                                )}
                            </Box>
                        </Box>
                    </div>
                </Container>
            </RootStyle>
        </Page>
    )
}

const CreateMediaCarousel = (props) => {
    return (
        <Box overflow={'auto'}>
            <Box display={'flex'} my={2}>
             
                <Box
                    onClick={() =>
                        document.getElementById('media-add-new-video').click()
                    }
                    mx={1}
                    height={82}
                    width={50}
                    display={'flex'}
                    flexDirection={'row'}
                    alignItems={'center'}
                    overflowY={'auto'}
                    borderRadius={1}
                    bgcolor={'rgba(217, 217, 217, 0.5)'}
                    style={{ opacity: props.videos?.length > 0 ? 0.6 : 1 }}
                >
                    <Box ml={0.4}>
                        <IconButton>
                            <Iconify
                                icon={'ant-design:plus-outlined'}
                                width={28}
                                height={28}
                                color="common.white"
                            />
                        </IconButton>
                        <Box borderRadius={1} overflow={'hidden'}></Box>
                    </Box>
                </Box>
                {props.videos?.map((item, index) => {
                    return (
                        <Box
                            mx={1}
                            height={'80px'}
                            width={'50px'}
                            display={'flex'}
                            flexDirection={'row'}
                            alignItems={'center'}
                            overflowY={'auto'}
                            onClick={() => props.setCurrent(index)}
                        >
                            <Box position={'relative'}>
                                <IconButton
                                    style={{
                                        position: 'absolute',
                                        top: -16,
                                        right: -16,
                                        zIndex: 100,
                                    }}
                                    onClick={(e) => {
                                        e.stopPropagation()
                                        props.removeVideo(index)
                                    }}
                                >
                                  
                                </IconButton>
                                <Box
                                    borderRadius={1}
                                    border={1}
                                    borderColor={
                                        props.currentExercise == index
                                            ? 'red'
                                            : '#fff'
                                    }
                                    position={'relative'}
                                    overflow={'hidden'}
                                    bgcolor={'#D3D3D3'}
                                >
                                    <Box
                                        borderRadius={1}
                                        overflow={'hidden'}
                                        height={80}
                                        width={48}
                                    >
                                        <Box
                                            position={'absolute'}
                                            width={'100%'}
                                            height={'100%'}
                                            top={0}
                                            alignItems={'center'}
                                            display={'flex'}
                                            justifyContent={'center'}
                                        >
                                            <Iconify
                                                icon={
                                                    'material-symbols:play-circle'
                                                }
                                                color="common.white"
                                                width={24}
                                                height={24}
                                            />
                                        </Box>
                                        {typeof item == 'string' ? (
                                            <VideoImage link={item} />
                                        ) : (
                                            <VideoComponent
                                                component={ReactPlayer}
                                                fileName={item.name}
                                                url={URL.createObjectURL(item)}
                                                //   controls
                                                loop
                                                controls={false}
                                                autoPlay={true}
                                                responsive={true}
                                                playsinline={true}
                                                playing={false}
                                                width="auto"
                                                height={'100%'}
                                                style={{
                                                    display: 'flex',
                                                    justifyContent: 'center',
                                                    alignItems: 'center',
                                                    borderRadius: '20px',
                                                    width: '100%',
                                                    height: '100%',
                                                    '& video': {
                                                        borderRadius: '20px',
                                                    },
                                                }}
                                            />
                                        )}
                                    </Box>
                                </Box>
                            </Box>
                        </Box>
                    )
                })}
            </Box>
        </Box>
    )
}

const VideoComponent = memo(
    (props) => {
        let Video = props.component
        return <Video {...props} />
    },
    (p, n) => p.fileName == n.fileName
)

const VideoImage = (props) => {
    const [url, setUrl] = useState('')
    useEffect(() => {
        setUrl(getThumbnail(props.link))
    }, [props.link])

    return (
        <ImageWithFallback
            onClick={props.onClick}
            variant="rounded"
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
            src={url || '/images/instructor/exerciseImage.png'}
        />
    )
}
